    function renderFeeReportRows(tabId, rows) {
        const colspans = { vault: 8, conversion: 8, collection: 8, payout: 8 };
        if (!rows.length) {
            return `<tr><td colspan="${colspans[tabId] || 8}" style="padding: 48px 24px; text-align: center; color: #64748B;">No fee records matched your current filters.</td></tr>`;
        }

        const renderStatus = (status) => {
            const pill = getOrderReportStatusPill(status);
            return `<span style="background: ${pill.bg}; color: ${pill.color}; padding: 4px 10px; border-radius: 999px; font-size: 11px; font-weight: 700;">${pill.label}</span>`;
        };

        return rows.map(row => `
            <tr onclick="alert('Viewing Fee Record...')">
                <td style="font-family: monospace; font-size: 12px; color: #2563EB;">${row.feeId}</td>
                <td class="text-muted">${row.chargedOn}</td>
                <td style="font-family: monospace; font-size: 12px; color: #2563EB;">${row.orderId}</td>
                <td>${row.feeType}</td>
                <td>${row.currency}</td>
                <td class="text-right">${row.baseAmount}</td>
                <td class="text-right font-medium">${row.feeAmount}</td>
                <td>${renderStatus(row.status)}</td>
            </tr>
        `).join('');
    }

    function renderFeeReportsPage() {
        const activeTab = FEE_REPORT_TABS.find(tab => tab.id === activeFeeReportTab) || FEE_REPORT_TABS[0];
        const searchValue = document.getElementById('fee-reports-search')?.value?.trim().toLowerCase() || '';
        const statusValue = document.getElementById('fee-reports-status')?.value || 'all';
        const startDateValue = document.getElementById('fee-reports-start-date')?.value || '';
        const endDateValue = document.getElementById('fee-reports-end-date')?.value || '';

        const rows = FEE_REPORT_DATA[activeTab.id].filter(row => {
            const matchesSearch = !searchValue || Object.values(row).join(' ').toLowerCase().includes(searchValue);
            const matchesStatus = statusValue === 'all' || normalizeOrderStatus(row.status) === statusValue;
            let matchesDate = true;
            if (startDateValue || endDateValue) {
                const rowDateString = row.chargedOn || '';
                if (startDateValue) matchesDate = matchesDate && rowDateString.toLowerCase().includes(startDateValue.split('-')[2]);
                if (endDateValue) matchesDate = matchesDate && rowDateString.toLowerCase().includes(endDateValue.split('-')[2]);
            }
            return matchesSearch && matchesStatus && matchesDate;
        });

        const tableMeta = {
            vault: {
                description: 'Fees charged for vault transfers and top up related processing.',
                statusOptions: ['In Progress', 'Completed']
            },
            conversion: {
                description: 'FX spread and conversion-related charges by conversion order.',
                statusOptions: ['Completed', 'In Progress']
            },
            collection: {
                description: 'Collection and checkout processing fees charged on inbound payments.',
                statusOptions: ['Completed']
            },
            payout: {
                description: 'Payout processing and network fees for outbound disbursement activity.',
                statusOptions: ['Awaiting Approval', 'Completed']
            }
        }[activeTab.id];

        contentBody.innerHTML = `
            <div class="fade-in" style="display: flex; flex-direction: column; gap: 20px;">
                <div class="card" style="padding: 24px;">
                    <h2 style="font-size: 24px; font-weight: 700; color: #0F172A; margin: 0 0 8px;">Fee Reports</h2>
                    <div style="font-size: 13px; color: #64748B; line-height: 1.6;">Review fee accruals and settled fee records by business line, with the fee basis and charge amount clearly separated.</div>
                </div>

                <div class="card" style="padding: 0; overflow: hidden;">
                    <div style="padding: 14px; border-bottom: 1px solid #E2E8F0; background: linear-gradient(180deg, #FFFFFF 0%, #F8FAFC 100%);">
                        <div style="display: flex; gap: 10px; flex-wrap: wrap;">
                            ${FEE_REPORT_TABS.map(tab => `
                                <button onclick="window.switchFeeReportTab('${tab.id}')" style="
                                    padding: 12px 16px;
                                    border-radius: 14px;
                                    border: 1px solid ${tab.id === activeFeeReportTab ? tab.tone.border : '#E2E8F0'};
                                    background: ${tab.id === activeFeeReportTab ? `linear-gradient(180deg, ${tab.tone.bg} 0%, #FFFFFF 100%)` : '#FFFFFF'};
                                    color: ${tab.id === activeFeeReportTab ? tab.tone.color : '#475569'};
                                    font-size: 13px;
                                    font-weight: ${tab.id === activeFeeReportTab ? '700' : '600'};
                                    box-shadow: ${tab.id === activeFeeReportTab ? '0 10px 22px rgba(15, 23, 42, 0.08)' : 'none'};
                                    cursor: pointer;
                                    display: inline-flex;
                                    align-items: center;
                                    gap: 8px;
                                ">
                                    <span style="width: 8px; height: 8px; border-radius: 999px; background: ${tab.tone.color}; opacity: ${tab.id === activeFeeReportTab ? '1' : '0.35'};"></span>
                                    ${tab.label}
                                </button>
                            `).join('')}
                        </div>
                    </div>

                    <div style="padding: 20px 24px; border-bottom: 1px solid #E2E8F0; display: flex; align-items: flex-start; justify-content: space-between; gap: 16px; flex-wrap: wrap; background: #FCFDFE;">
                        <div>
                            <div style="display: flex; align-items: center; gap: 10px; flex-wrap: wrap;">
                                <h3 style="font-size: 18px; font-weight: 700; color: #0F172A; margin: 0;">${activeTab.label}</h3>
                                <span style="font-size: 11px; font-weight: 700; color: ${activeTab.tone.color}; background: ${activeTab.tone.bg}; border: 1px solid ${activeTab.tone.border}; padding: 4px 10px; border-radius: 999px;">Fees</span>
                            </div>
                            <div style="font-size: 12px; color: #64748B; margin-top: 4px;">${tableMeta.description}</div>
                        </div>
                        <button class="btn btn-outline" style="padding: 8px 14px; font-size: 13px; display: flex; align-items: center; gap: 6px;">
                            <i data-lucide="download" style="width: 14px; height: 14px;"></i>
                            Export ${activeTab.label}
                        </button>
                    </div>

                    <div style="padding: 18px 24px; border-bottom: 1px solid #E2E8F0; background: #FCFDFE; display: grid; grid-template-columns: 1fr 1.6fr 0.8fr; gap: 14px;">
                        <div style="position: relative;">
                            <i data-lucide="search" style="position: absolute; left: 12px; top: 50%; transform: translateY(-50%); width: 15px; height: 15px; color: #94A3B8;"></i>
                            <input id="fee-reports-search" type="text" value="${document.getElementById('fee-reports-search')?.value || ''}" oninput="window.renderFeeReportsPage()" placeholder="Search..." style="width: 100%; padding: 11px 14px 11px 38px; border: 1px solid #E2E8F0; border-radius: 10px; font-size: 13px; color: #0F172A; background: #FFFFFF; outline: none;">
                        </div>
                        <div style="display: flex; align-items: center; gap: 8px; background: #FFFFFF; border: 1px solid #E2E8F0; border-radius: 10px; padding: 0 12px;">
                            <input id="fee-reports-start-date" type="date" value="${document.getElementById('fee-reports-start-date')?.value || ''}" onchange="window.renderFeeReportsPage()" style="border: none; background: transparent; font-size: 12px; color: #0F172A; outline: none; padding: 11px 0; width: 110px;">
                            <span style="color: #94A3B8; font-size: 12px; font-weight: 600;">to</span>
                            <input id="fee-reports-end-date" type="date" value="${document.getElementById('fee-reports-end-date')?.value || ''}" onchange="window.renderFeeReportsPage()" style="border: none; background: transparent; font-size: 12px; color: #0F172A; outline: none; padding: 11px 0; width: 110px;">
                        </div>
                        <select id="fee-reports-status" onchange="window.renderFeeReportsPage()" style="width: 100%; padding: 11px 14px; border: 1px solid #E2E8F0; border-radius: 10px; font-size: 13px; color: #0F172A; background: #FFFFFF; outline: none;">
                            <option value="all">All Statuses</option>
                            ${tableMeta.statusOptions.map(status => `<option value="${status}" ${statusValue === status ? 'selected' : ''}>${status}</option>`).join('')}
                        </select>
                    </div>

                    <div class="table-responsive">
                        <table class="data-table">
                            <thead>
                                <tr>
                                    <th>Fee ID</th>
                                    <th>Charged On</th>
                                    <th>Order ID</th>
                                    <th>Fee Type</th>
                                    <th>Currency</th>
                                    <th class="text-right">Fee Basis</th>
                                    <th class="text-right">Fee Amount</th>
                                    <th>Status</th>
                                </tr>
                            </thead>
                            <tbody>
                                ${renderFeeReportRows(activeTab.id, rows)}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
        `;
        lucide.createIcons();
    }

    function addReportRecord(typeName, fileName, period) {
        generatedReportHistory.unshift({ createdOn: new Date(), typeName, fileName, period: period || '' });
        if (currentPage === 'Report Center') renderReportCenterPage();
    }

    window.setDownloadFilter = function(key, value) {
        downloadFilters[key] = value;
        renderReportCenterPage();
    };

    function renderReportCenterPage() {
        const cards = [
            {
                title: 'Balance activity report',
                badge: 'Asset Vaults',
                description: 'Record of every settled wallet transaction. Used to track running account balances across currencies.',
                icon: 'wallet',
                iconBg: 'linear-gradient(180deg, #FFF7ED 0%, #FFEDD5 100%)',
                iconColor: '#F97316',
                action: 'balance'
            },
            {
                title: 'Account statement',
                badge: 'Asset Vaults',
                description: 'An official vault statement covering all currencies within a Stablecoin Vault or Fiat Vault, with per-currency transaction history and financial summary.',
                icon: 'file-text',
                iconBg: 'linear-gradient(180deg, #F8FAFC 0%, #F1F5F9 100%)',
                iconColor: '#94A3B8',
                action: 'statement'
            },
            {
                title: 'Business Order Report',
                badge: 'Collection, Payout',
                description: 'Detailed record of pending and settled transactions, including all individual payment attempts within a Payments batch settlement.',
                icon: 'receipt-text',
                iconBg: 'linear-gradient(180deg, #FFF7ED 0%, #FFE4E6 100%)',
                iconColor: '#FB7185',
                action: 'reconciliation'
            },
            {
                title: 'Settlement and fee report',
                badge: 'Collection, Payout',
                description: 'Settled payment transactions and fees in the selected date range.',
                icon: 'files',
                iconBg: 'linear-gradient(180deg, #F8FAFC 0%, #F1F5F9 100%)',
                iconColor: '#06B6D4',
                action: 'settlement'
            }
        ];

        contentBody.innerHTML = `
            <div class="fade-in" style="max-width: 1240px; margin: 0 auto; display: flex; flex-direction: column; gap: 48px; padding-bottom: 60px;">
                <div style="display: grid; grid-template-columns: 1fr 1fr; gap: 20px;">
                    ${cards.map(card => {
                        const sel = reportCardSelections[card.action];
                        const isDaily = sel.type === 'daily';
                        const isRecon      = card.action === 'reconciliation';
                        const isSettlement = card.action === 'settlement';
                        const isStatement  = card.action === 'statement';
                        // Daily: max = yesterday
                        const today = new Date();
                        const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
                        const maxDay = yesterday.toISOString().split('T')[0];
                        // Monthly: max = last month, min = 6 months ago
                        const lastMonth = new Date(today.getFullYear(), today.getMonth() - 1, 1);
                        const sixMonthsAgo = new Date(today.getFullYear(), today.getMonth() - 6, 1);
                        const maxMonth = `${lastMonth.getFullYear()}-${String(lastMonth.getMonth()+1).padStart(2,'0')}`;
                        const minMonth = `${sixMonthsAgo.getFullYear()}-${String(sixMonthsAgo.getMonth()+1).padStart(2,'0')}`;
                        const hasDate = sel.value !== '';
                        const hasOrderType         = !isRecon      || (sel.orderType    && sel.orderType    !== '');
                        const hasReportSubType     = !isSettlement || (sel.reportSubType && sel.reportSubType !== '');
                        const hasStatementVaultType = !isStatement  || (sel.vaultType && sel.vaultType !== '');
                        const hasValue = hasDate && hasOrderType && hasReportSubType && hasStatementVaultType;
                        const ORDER_TYPES = ['Collection-Checkout', 'Collection-Invoice', 'Payout', 'Conversion'];
                        return `
                        <div class="card" style="padding: 32px 34px; min-height: 300px; display: flex; flex-direction: column; justify-content: space-between; border-radius: 16px; border: 1px solid #E2E8F0; box-shadow: 0 12px 30px rgba(15, 23, 42, 0.05);">
                            <div style="display: flex; align-items: flex-start; gap: 20px;">
                                <div style="width: 78px; height: 78px; border-radius: 22px; background: ${card.iconBg}; display: flex; align-items: center; justify-content: center; flex-shrink: 0;">
                                    <i data-lucide="${card.icon}" style="width: 38px; height: 38px; color: ${card.iconColor};"></i>
                                </div>
                                <div style="display: flex; flex-direction: column; gap: 14px;">
                                    <div style="display: flex; align-items: center; gap: 8px; flex-wrap: wrap;">
                                        <h2 style="font-size: 22px; font-weight: 800; color: #0F172A; margin: 0; letter-spacing: -0.02em;">${card.title}</h2>
                                        ${card.badge.split(',').map(tag => `
                                            <span style="padding: 6px 10px; border-radius: 8px; background: #EDE9FE; color: #4F46E5; font-size: 12px; font-weight: 800;">${tag.trim()}</span>
                                        `).join('')}
                                    </div>
                                    <div style="font-size: 14px; color: #0F172A; line-height: 1.7;">${card.description}</div>
                                </div>
                            </div>
                            <div style="display: flex; flex-direction: column; gap: 14px; margin-top: 24px;">
                                ${isRecon ? `
                                <!-- 1. Order Type selector (reconciliation only, shown first) -->
                                <div style="display: flex; align-items: center; gap: 12px;">
                                    <span style="font-size: 13px; font-weight: 600; color: #64748B; white-space: nowrap; width: 76px;">Order Type</span>
                                    <div style="position: relative; flex: 1;">
                                        <select onchange="window.setReportOrderType(this.value)" style="width: 100%; padding: 9px 36px 9px 14px; border: 1px solid ${sel.orderType ? '#4F46E5' : '#E2E8F0'}; border-radius: 10px; background: ${sel.orderType ? '#EDE9FE' : '#FFFFFF'}; color: ${sel.orderType ? '#4F46E5' : '#94A3B8'}; font-size: 13px; font-weight: 600; outline: none; cursor: pointer; appearance: none; -webkit-appearance: none;">
                                            <option value="" disabled ${!sel.orderType ? 'selected' : ''}>Select order type...</option>
                                            ${ORDER_TYPES.map(ot => `<option value="${ot}" ${sel.orderType === ot ? 'selected' : ''} style="color: #0F172A;">${ot}</option>`).join('')}
                                        </select>
                                        <i data-lucide="chevron-down" style="width: 15px; height: 15px; color: ${sel.orderType ? '#4F46E5' : '#94A3B8'}; position: absolute; right: 12px; top: 50%; transform: translateY(-50%); pointer-events: none;"></i>
                                    </div>
                                </div>` : ''}
                                ${isRecon ? `
                                <!-- 2+3. 报表类型 toggle + date picker + Generate (single row for recon) -->
                                <div style="display: flex; align-items: center; gap: 10px;">
                                    <div style="display: flex; background: #F1F5F9; border-radius: 10px; padding: 3px; gap: 2px; flex-shrink: 0;">
                                        <button onclick="window.setReportCardType('${card.action}', 'daily')" style="padding: 7px 18px; border-radius: 8px; border: none; cursor: pointer; font-size: 13px; font-weight: 700; transition: all 0.15s; ${isDaily ? 'background: #FFFFFF; color: #4F46E5; box-shadow: 0 1px 4px rgba(15,23,42,0.10);' : 'background: transparent; color: #64748B;'}">日报</button>
                                        <button onclick="window.setReportCardType('${card.action}', 'monthly')" style="padding: 7px 18px; border-radius: 8px; border: none; cursor: pointer; font-size: 13px; font-weight: 700; transition: all 0.15s; ${!isDaily ? 'background: #FFFFFF; color: #4F46E5; box-shadow: 0 1px 4px rgba(15,23,42,0.10);' : 'background: transparent; color: #64748B;'}">月报</button>
                                    </div>
                                    <div style="display: flex; align-items: center; gap: 8px; border: 1px solid #E2E8F0; border-radius: 10px; padding: 10px 14px; background: #FFFFFF; flex: 1; cursor: pointer;">
                                        <i data-lucide="calendar" style="width: 16px; height: 16px; color: #64748B; flex-shrink: 0;"></i>
                                        ${isDaily
                                            ? `<input type="date" id="report-date-${card.action}" value="${sel.value}" max="${maxDay}" onchange="window.setReportCardValue('${card.action}', this.value)" style="border: none; background: transparent; font-size: 13px; color: ${hasDate ? '#0F172A' : '#94A3B8'}; outline: none; width: 100%; cursor: pointer; font-weight: 500;">`
                                            : `<input type="month" id="report-date-${card.action}" value="${sel.value}" min="${minMonth}" max="${maxMonth}" onchange="window.setReportCardValue('${card.action}', this.value)" style="border: none; background: transparent; font-size: 13px; color: ${hasDate ? '#0F172A' : '#94A3B8'}; outline: none; width: 100%; cursor: pointer; font-weight: 500;">`
                                        }
                                    </div>
                                    <button class="btn" onclick="${hasValue ? `window.generateReport('${card.action}', '${sel.type}', '${sel.value}')` : ''}" style="padding: 10px 20px; font-size: 14px; font-weight: 800; white-space: nowrap; flex-shrink: 0; ${hasValue ? 'background: #4F46E5; color: #FFFFFF; border-color: #4F46E5; cursor: pointer; opacity: 1;' : 'background: #F1F5F9; color: #94A3B8; border-color: #E2E8F0; cursor: not-allowed; opacity: 0.7;'}">Generate</button>
                                </div>` : `
                                ${isStatement ? `
                                <!-- Account Statement vault type selector -->
                                <div style="display: flex; align-items: center; gap: 12px;">
                                    <span style="font-size: 13px; font-weight: 600; color: #64748B; white-space: nowrap; width: 76px;">Vault</span>
                                    <div style="display: flex; gap: 8px; flex: 1;">
                                        ${(window.currentLicenseMode === 'MSO' ? ['Fiat Vault'] : ['Stablecoin Vault','Fiat Vault']).map(vt => `
                                        <button onclick="window.setStatementVaultType('${vt}')" style="flex: 1; padding: 9px 10px; border-radius: 10px; border: 1px solid ${sel.vaultType === vt ? '#0072F7' : '#E2E8F0'}; background: ${sel.vaultType === vt ? '#EFF6FF' : '#FFFFFF'}; color: ${sel.vaultType === vt ? '#0072F7' : '#94A3B8'}; font-size: 12px; font-weight: 700; cursor: pointer; transition: all 0.15s; white-space: nowrap;">${vt}</button>
                                        `).join('')}
                                    </div>
                                </div>` : ''}
                                ${isSettlement ? `
                                <!-- Settlement report sub-type selector -->
                                <div style="display: flex; align-items: center; gap: 12px;">
                                    <span style="font-size: 13px; font-weight: 600; color: #64748B; white-space: nowrap; width: 76px;">Report</span>
                                    <div style="position: relative; flex: 1;">
                                        <select onchange="window.setSettlementReportType(this.value)" style="width: 100%; padding: 9px 36px 9px 14px; border: 1px solid ${sel.reportSubType ? '#4F46E5' : '#E2E8F0'}; border-radius: 10px; background: ${sel.reportSubType ? '#EDE9FE' : '#FFFFFF'}; color: ${sel.reportSubType ? '#4F46E5' : '#94A3B8'}; font-size: 13px; font-weight: 600; outline: none; cursor: pointer; appearance: none; -webkit-appearance: none;">
                                            <option value="" disabled ${!sel.reportSubType ? 'selected' : ''}>Select report type...</option>
                                            ${['Settlement Report','Fee Report','Fee Summary Report'].map(rt => `<option value="${rt}" ${sel.reportSubType === rt ? 'selected' : ''} style="color: #0F172A;">${rt}</option>`).join('')}
                                        </select>
                                        <i data-lucide="chevron-down" style="width: 15px; height: 15px; color: ${sel.reportSubType ? '#4F46E5' : '#94A3B8'}; position: absolute; right: 12px; top: 50%; transform: translateY(-50%); pointer-events: none;"></i>
                                    </div>
                                </div>` : ''}
                                <!-- 2. Report type toggle -->
                                <div style="display: flex; align-items: center; gap: 12px;">
                                    <span style="font-size: 13px; font-weight: 600; color: #64748B; white-space: nowrap; ${(isSettlement || isStatement) ? 'width: 76px;' : ''}">报表类型</span>
                                    <div style="display: flex; background: #F1F5F9; border-radius: 10px; padding: 3px; gap: 2px;">
                                        <button onclick="window.setReportCardType('${card.action}', 'daily')" style="padding: 7px 18px; border-radius: 8px; border: none; cursor: pointer; font-size: 13px; font-weight: 700; transition: all 0.15s; ${isDaily ? 'background: #FFFFFF; color: #4F46E5; box-shadow: 0 1px 4px rgba(15,23,42,0.10);' : 'background: transparent; color: #64748B;'}">日报</button>
                                        <button onclick="window.setReportCardType('${card.action}', 'monthly')" style="padding: 7px 18px; border-radius: 8px; border: none; cursor: pointer; font-size: 13px; font-weight: 700; transition: all 0.15s; ${!isDaily ? 'background: #FFFFFF; color: #4F46E5; box-shadow: 0 1px 4px rgba(15,23,42,0.10);' : 'background: transparent; color: #64748B;'}">月报</button>
                                    </div>
                                </div>
                                <!-- 3. Date / Month picker + Generate -->
                                <div style="display: flex; align-items: center; justify-content: space-between; gap: 12px;">
                                    <div style="display: flex; align-items: center; gap: 8px; border: 1px solid #E2E8F0; border-radius: 10px; padding: 10px 14px; background: #FFFFFF; flex: 1; cursor: pointer;">
                                        <i data-lucide="calendar" style="width: 16px; height: 16px; color: #64748B; flex-shrink: 0;"></i>
                                        ${isDaily
                                            ? `<input type="date" id="report-date-${card.action}" value="${sel.value}" max="${maxDay}" onchange="window.setReportCardValue('${card.action}', this.value)" style="border: none; background: transparent; font-size: 13px; color: ${hasDate ? '#0F172A' : '#94A3B8'}; outline: none; width: 100%; cursor: pointer; font-weight: 500;">`
                                            : `<input type="month" id="report-date-${card.action}" value="${sel.value}" min="${minMonth}" max="${maxMonth}" onchange="window.setReportCardValue('${card.action}', this.value)" style="border: none; background: transparent; font-size: 13px; color: ${hasDate ? '#0F172A' : '#94A3B8'}; outline: none; width: 100%; cursor: pointer; font-weight: 500;">`
                                        }
                                    </div>
                                    <button class="btn" onclick="${hasValue ? `window.generateReport('${card.action}', '${sel.type}', '${sel.value}')` : ''}" style="padding: 10px 20px; font-size: 14px; font-weight: 800; white-space: nowrap; ${hasValue ? 'background: #4F46E5; color: #FFFFFF; border-color: #4F46E5; cursor: pointer; opacity: 1;' : 'background: #F1F5F9; color: #94A3B8; border-color: #E2E8F0; cursor: not-allowed; opacity: 0.7;'}">Generate</button>
                                </div>`}
                            </div>
                        </div>`;
                    }).join('')}
                </div>

                <div>
                    <h2 style="font-size: 24px; font-weight: 900; color: #0F172A; margin: 0 0 10px; letter-spacing: -0.02em;">Download generated reports</h2>
                    <div style="font-size: 14px; color: #64748B; margin-bottom: 28px;">Generate a report using the cards above — it will appear here automatically. Records are available for 30 days.</div>

                    <div class="card" style="padding: 24px; border-radius: 12px; background: #FFFFFF;">
                        ${(() => {
                            // ── filter helpers ───────────────────────────────────────────
                            const TYPE_CATS = ['Balance Activity Report','Account Statement','Business Order Report','Settlement Report','Fee Report','Fee Summary Report'];
                            function typeCategory(typeName) {
                                if (typeName.startsWith('Business Order Report')) return 'Business Order Report';
                                if (typeName.startsWith('Account Statement'))      return 'Account Statement';
                                return typeName;
                            }
                            const presentCats = new Set(generatedReportHistory.map(r => typeCategory(r.typeName)));
                            const visibleCats = TYPE_CATS.filter(c => presentCats.has(c));

                            function pillBtn(label, filterKey, value) {
                                const isActive = downloadFilters[filterKey] === value;
                                return `<button onclick="window.setDownloadFilter('${filterKey}','${value}')" style="padding: 6px 14px; border-radius: 8px; border: none; font-size: 13px; font-weight: 700; cursor: pointer; transition: all 0.15s; ${isActive ? 'background:#4F46E5;color:#FFFFFF;' : 'background:#F1F5F9;color:#64748B;'}">${label}</button>`;
                            }

                            // ── filtered records ─────────────────────────────────────────
                            const filtered = generatedReportHistory.filter(r => {
                                const typeOk = downloadFilters.type === 'All' || typeCategory(r.typeName) === downloadFilters.type;
                                const statusOk = downloadFilters.status === 'All' || true; // all Completed
                                return typeOk && statusOk;
                            });

                            const filtersUI = generatedReportHistory.length > 0 ? `
                            <div style="display: flex; align-items: flex-start; gap: 24px; flex-wrap: wrap; padding-bottom: 20px; border-bottom: 1px solid #F1F5F9; margin-bottom: 4px;">
                                <div style="display: flex; align-items: center; gap: 8px; flex-wrap: wrap;">
                                    <span style="font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.08em; white-space: nowrap; padding: 6px 0;">Type</span>
                                    ${pillBtn('All','type','All')}
                                    ${visibleCats.map(c => pillBtn(c, 'type', c)).join('')}
                                </div>
                                <div style="display: flex; align-items: center; gap: 8px; margin-left: auto;">
                                    <span style="font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.08em; white-space: nowrap; padding: 6px 0;">Status</span>
                                    ${pillBtn('All','status','All')}
                                    ${pillBtn('Completed','status','Completed')}
                                </div>
                            </div>` : '';

                            const tableBody = filtered.length === 0 ? `
                                    <tr><td colspan="6" style="padding: 48px 16px; text-align: center; color: #94A3B8; font-size: 14px; font-weight: 500;">
                                        ${generatedReportHistory.length === 0 ? 'No reports generated yet. Use the cards above to generate a report.' : 'No records match the selected filters.'}
                                    </td></tr>` :
                                filtered.map(rec => {
                                    const d   = rec.createdOn;
                                    const now = new Date();
                                    const isToday = d.toDateString() === now.toDateString();
                                    const hh  = String(d.getHours()).padStart(2,'0');
                                    const mm  = String(d.getMinutes()).padStart(2,'0');
                                    const dateStr = isToday ? `Today, ${hh}:${mm}` : d.toISOString().slice(0,10);
                                    return `
                                    <tr style="border-bottom: 1px solid #F1F5F9;">
                                        <td style="padding: 18px 16px; font-size: 14px; color: #0F172A; font-weight: 500; white-space: nowrap;">${dateStr}</td>
                                        <td style="padding: 18px 16px; font-size: 14px; color: #0F172A; font-weight: 500;">${rec.typeName}</td>
                                        <td style="padding: 18px 16px; font-size: 14px; color: #64748B; font-weight: 500; white-space: nowrap;">${rec.period || '—'}</td>
                                        <td style="padding: 18px 16px; font-size: 13px; color: #475569; font-weight: 500; word-break: break-all;">${rec.fileName}</td>
                                        <td style="padding: 18px 16px;"><span style="padding: 5px 12px; border-radius: 6px; background: #DCFCE7; color: #166534; font-size: 12px; font-weight: 800;">Completed</span></td>
                                        <td style="padding: 18px 16px; text-align: right;"><button onclick="alert('File was already downloaded to your device. Re-generate the report to download again.')" title="Downloaded" style="background:none;border:none;color:#4F46E5;cursor:pointer;display:inline-flex;align-items:center;transition:transform 0.2s;" onmouseover="this.style.transform='translateY(-1px)'" onmouseout="this.style.transform='translateY(0)'"><i data-lucide="download" style="width:18px;height:18px;"></i></button></td>
                                    </tr>`;
                                }).join('');

                            return `
                            ${filtersUI}
                            <div style="margin-top: 20px; overflow-x: auto;">
                                <table style="width: 100%; border-collapse: collapse; min-width: 900px;">
                                    <thead>
                                        <tr style="border-bottom: 2px solid #F1F5F9;">
                                            <th style="padding: 14px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.1em; width: 150px;">Created On</th>
                                            <th style="padding: 14px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.1em; width: 240px;">Report Type</th>
                                            <th style="padding: 14px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.1em; width: 110px;">Period</th>
                                            <th style="padding: 14px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.1em;">Filename</th>
                                            <th style="padding: 14px 16px; text-align: left; font-size: 11px; font-weight: 800; color: #94A3B8; text-transform: uppercase; letter-spacing: 0.1em; width: 120px;">Status</th>
                                            <th style="padding: 14px 16px; width: 50px;"></th>
                                        </tr>
                                    </thead>
                                    <tbody>${tableBody}</tbody>
                                </table>
                            </div>
                            <div style="margin-top: 20px; padding-top: 20px; border-top: 1px solid #F1F5F9; display: flex; align-items: center; justify-content: flex-end;">
                                <div style="font-size: 13px; color: #64748B; font-weight: 500;">
                                    ${filtered.length} of ${generatedReportHistory.length} record${generatedReportHistory.length !== 1 ? 's' : ''}
                                </div>
                            </div>`;
                        })()}
                    </div>
                </div>
            </div>
        `;
        lucide.createIcons();
    }

